import{_ as e,o as r,c as a,a2 as p}from"./chunks/framework.BWuWLRhz.js";const o="/images/the-bunny-manifesto/hippo-bunny.jpg",s="/images/the-bunny-manifesto/2-NORMAL.jpg",n="/images/the-bunny-manifesto/6-don-t-look-like-bunnies-or-any-normal-creature.jpeg",g="/images/the-bunny-manifesto/3-cute2.jpg",A="/images/the-bunny-manifesto/4.jpg",i="/images/the-bunny-manifesto/5-dick.jpg",m="/images/the-bunny-manifesto/7-normal-hapless.jpg",b="/images/the-bunny-manifesto/8-hamster.jpeg",h="/images/the-bunny-manifesto/9-cat.jpg",l="/images/the-bunny-manifesto/10-bulldog.jpg",c="/images/the-bunny-manifesto/11-rat.jpg",f="/images/the-bunny-manifesto/12-kangaroo.png",_="/images/the-bunny-manifesto/13-walrus.jpg",u="/images/the-bunny-manifesto/14-lion.jpg",y="/images/the-bunny-manifesto/15-lion-shitty-attempt.jpg",k="/images/the-bunny-manifesto/17-wild-things.jpg",w="/images/the-bunny-manifesto/18-tongue.jpg",j="/images/the-bunny-manifesto/19-airquote.jpg",d="/images/the-bunny-manifesto/20-low-self-esteem.jpeg",Q="/images/the-bunny-manifesto/21-emo.jpg",I="/images/the-bunny-manifesto/23-cute1.jpeg",E="/images/the-bunny-manifesto/22-owners-pleased-with-how-that-turned-out.jpg",U="/images/the-bunny-manifesto/24-owner.jpg",T="/images/the-bunny-manifesto/25-dog.jpg",W="/images/the-bunny-manifesto/26-meth-possum.jpg",M="/images/the-bunny-manifesto/27-wasp.jpg",v="/images/the-bunny-manifesto/28-fucking-hate-me.jpeg",q="/images/the-bunny-manifesto/29-grandparents-ear.jpg",z="/images/the-bunny-manifesto/30-boo-boo.jpeg",P="/images/the-bunny-manifesto/31-mean-headmaster.jpeg",B="/images/the-bunny-manifesto/33-m70s.jpg",Y="/images/the-bunny-manifesto/35-regrets-decision.jpg",x="/images/the-bunny-manifesto/34-looney-tunes.jpg",O="/images/the-bunny-manifesto/36-forgot-to-stop-being-a-fetus.jpg",C="/images/the-bunny-manifesto/37-back-in-animal-territory.jpg",R="/images/the-bunny-manifesto/38-come-on.jpg",Z="/images/the-bunny-manifesto/39-huge.jpg",J="/images/the-bunny-manifesto/40-come-on3.jpeg",L="/images/the-bunny-manifesto/41-rock-bottom-2.jpeg",D="/images/the-bunny-manifesto/pinit_fg_en_rect_gray_20.png",$=JSON.parse('{"title":"The Bunny Manifesto","description":"","frontmatter":{"title":"The Bunny Manifesto","titleZh":"兔子宣言","date":"2013-08-09T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/08/the-bunny-manifesto.html","slug":"the-bunny-manifesto"},"headers":[],"relativePath":"posts/the-bunny-manifesto.md","filePath":"posts/the-bunny-manifesto.md","lastUpdated":1782886257000}'),F={name:"posts/the-bunny-manifesto.md"};function V(N,t,S,G,H,K){return r(),a("div",null,[...t[0]||(t[0]=[p('<h1 id="兔子宣言-·-the-bunny-manifesto" tabindex="-1">兔子宣言 · The Bunny Manifesto <a class="header-anchor" href="#兔子宣言-·-the-bunny-manifesto" aria-label="Permalink to &quot;兔子宣言 · The Bunny Manifesto&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/08/the-bunny-manifesto.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/08/the-bunny-manifesto.html</a> · 2013-08-09</p></blockquote><p>用一篇讲述人类最恐怖悲剧死亡人数的<a href="https://waitbutwhy.com/2013/08/the-death-toll-comparison-breakdown.html" target="_blank" rel="noreferrer">令人不寒而栗的文章</a>,后面紧跟着一篇叫《兔子宣言》的博文,是不是有点怪?周一发的文章缩略图是一堆圆圈、每个圆圈代表成千上万条逝去的生命,周四紧接着发的文章缩略图却是一只肥胖的兔子面无表情地盯着镜头——这是不是让这网站变成了一个他妈的挺怪异的网站?</p><p>我很想为 Wait But Why 的这种行为提供一个解释,但没有。我只能说,把我们拖进这个局面的,就是下面这只特定的肥兔子:</p><p><a href="https://3.bp.blogspot.com/-wuWyB7yNwOQ/UgRLFWy_ToI/AAAAAAAAExA/x0N0QJfq2U0/s1600/hippo+bunny.jpg" target="_blank" rel="noreferrer"><img src="'+o+'" alt=""></a></p><p>我在一次跟这事儿毫无关系的谷歌图片搜索中偶然看到了这张照片。“哦看,一只小河马,”我心想,点进去看特写,结果才发现这不是河马,而是一只<em>兔子</em>。我从没想过自己会把一只兔子错认成河马,但事实就是,我们面对面了。</p><p>事态进一步恶化,我意识到自己对“bunny”这个概念本身就一头雾水。bunny 和 rabbit 是一回事吗?那 hare 呢?我决定拿到谷歌图片上查一查。</p><p>结果让人不安。</p><p>我不仅搞不清 bunny 是什么——不仅谷歌图片也搞不清 bunny 是什么——<em>bunny 自己</em>都搞不清 bunny 是什么。</p><p>我在谷歌图片里先搜 bunny,再搜 rabbit,然后搜 hare,一路走下来,踏上了一条离奇的道路,遇到了一群各式各样、多少有点让人不安的生物。</p><p>这需要一次彻底的探索。请你坐稳了——我先警告你,这事儿要变得很怪了。</p><p>在开始之前,我想先破除在这次探索过程中被证明大错特错的三个迷思:</p><h3 id="迷思-1-兔子长得很正常。" tabindex="-1"><strong>迷思 1)兔子长得很正常。</strong> <a class="header-anchor" href="#迷思-1-兔子长得很正常。" aria-label="Permalink to &quot;**迷思 1)兔子长得很正常。**&quot;">​</a></h3><p>来看看我现在已经知道的、在兔子世界里完全属于异常的东西——一只长得正常的兔子:</p><p><a href="https://3.bp.blogspot.com/-NpBGYALbWvM/UgQb2Eb6PDI/AAAAAAAAEtE/EMICr-3iHlA/s1600/2+NORMAL.jpg" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a></p><p>这就是我一想到兔子时脑子里浮现的样子,你应该趁我还没在这篇文章里把“兔子就长这样”的观念撕得粉碎之前,先好好欣赏它一下。</p><p>事实证明,上面那只兔子只是个门面。这是兔子<em>希望</em>你以为它们长的样子。令人不安的现实是,它们更常见的“正常”长相是这样的:</p><p><a href="https://2.bp.blogspot.com/-ZpeQnV7h2eI/UgQb8RhULTI/AAAAAAAAEwk/BddDWIfffTo/s1600/6+don&#39;t+look+like+bunnies+or+any+normal+creature.jpeg" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p>这生物完全可以在一部科幻电影里冒充外星人。</p><h3 id="" tabindex="-1">** <a class="header-anchor" href="#" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>迷思 2)兔子很可爱。**</p><p>同样地,你大概会觉得兔子萌得不行,就像下面这只可人的小家伙。</p><p><a href="https://4.bp.blogspot.com/-HTvSYzA-pO4/UgQb4Zh_u0I/AAAAAAAAEuI/XwhtogT_1tA/s1600/3+cute2.jpg" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p><p>错。大多数兔子的可爱程度大概是这样:</p><p><a href="https://2.bp.blogspot.com/-P4yRQNoxz94/UgQb7Qz0WuI/AAAAAAAAEv0/_hWh4AQzTM8/s1600/4.jpg" target="_blank" rel="noreferrer"><img src="'+A+'" alt=""></a></p><h3 id="误解-3-兔子讨人喜欢。" tabindex="-1"><strong>误解 3)兔子讨人喜欢。</strong> <a class="header-anchor" href="#误解-3-兔子讨人喜欢。" aria-label="Permalink to &quot;**误解 3)兔子讨人喜欢。**&quot;">​</a></h3><p>我要你看看这只兔子:</p><p><a href="https://3.bp.blogspot.com/-O4HwfnafTGM/UgQb8dkUvzI/AAAAAAAAEwM/7aATFhIpnmw/s1600/5+dick.jpg" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p>想象一下和它待在一起是什么感觉。它看起来爱玩吗?看起来是那种一起玩会很愉快的家伙吗?</p><p>不,一点也不。它看起来就是个混蛋。它看起来会咬人,看起来自我中心,给我的感觉是跟它相处会烦得要死。</p><p>看到狗和猫的照片时,我通常都想去逗它们玩。它们跟人类是同一个频道的。但你根本没法想象兔子会像狗那样在你回家时兴奋地蹦到门口,也没法想象它会像猫那样冷静又有自我意识。我能想象兔子的样子只有两种:害怕的,和混蛋的。</p><p>所以咱们就把期望值放在正确的位置上吧。</p><p>好,开始深入。我们从一个简单的开始:</p><p><a href="https://3.bp.blogspot.com/-fGQcKmfH_hY/UgQb8T-A9WI/AAAAAAAAEwI/cT7SWjTiwg4/s1600/7+normal,+hapless.jpg" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p>这只兔子不像其他一些那么灾难,但你把它(我全都用「他」称呼,你们忍一下)和最上面那只「看起来正常的兔子」对比一下。正常兔子看起来就是一只没什么表情的普通动物。而这只看起来像个倒霉透顶的废柴。动物本不应该看起来带有人类形容词的,比如「倒霉」。然而兔子却经常看起来自带人类形容词,接下来你就会看到。</p><p>兔子还有一个奇怪的倾向,就是把自己弄得像别的动物。我不知道它们为什么觉得这样没问题,但这种行为在兔子群体中非常泛滥。比如,这只兔子在假扮仓鼠:</p><p><a href="https://4.bp.blogspot.com/-ClnCozyWt54/UgQb83J2AgI/AAAAAAAAEwQ/cN8f8yDm5-M/s1600/8+hamster.jpeg" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a></p><p>这只在装猫:</p><p><a href="https://1.bp.blogspot.com/-zVIUHM7CMJQ/UgQb9NpIOiI/AAAAAAAAEwg/E2X0lL3kc_A/s1600/9+cat.jpg" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p>这只,牛头犬:</p><p><a href="https://1.bp.blogspot.com/-2-vietx6ktg/UgQbzP19GMI/AAAAAAAAEr0/Sfy_uJtFCRI/s1600/10+bulldog.jpg" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p>这只兔子看起来像一只快哭出来的大老鼠:</p><p><a href="https://1.bp.blogspot.com/-XWFWk2l3qaQ/UgQbzGyYqDI/AAAAAAAAErs/_nv_Kj0o9aY/s1600/11+rat.jpg" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p><p>袋鼠:</p><p><a href="https://4.bp.blogspot.com/-WP9hss9CYAw/UgQbzVGtv9I/AAAAAAAAEss/MTYpaKoWQQQ/s1600/12+kangaroo.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p><p>在这两坨腮帮子上插两根獠牙,你的山寨海象就完成了:</p><p><a href="https://3.bp.blogspot.com/-nyWPhXhT_K8/UgQbzQghQAI/AAAAAAAAEr4/-9GvPLYOHI8/s1600/13+walrus.jpg" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a></p><p>这里我们看到一只迷你山寨版狮子。近乎精神失常的行为。但至少我得承认,它还原得挺准确:</p><p><a href="https://1.bp.blogspot.com/-fzIbyU0Bmbo/UgQbzmp8ruI/AAAAAAAAEsM/PJjmP-ZSjXo/s1600/14+lion.jpg" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p>一次不那么成功的尝试:</p><p><a href="https://1.bp.blogspot.com/-rPM2UWR_7Og/UgQbz1DCuoI/AAAAAAAAEsI/koE_Retknsw/s1600/15+lion+shitty+attempt.jpg" target="_blank" rel="noreferrer"><img src="'+y+'" alt=""></a></p><p>这只读了《野兽出没的地方》(Where The Wild Things Are),然后决定把自己打扮成书里的角色。</p><p><a href="https://2.bp.blogspot.com/-7_m8JuWOtf4/UgQb0ihpcUI/AAAAAAAAEsc/RE6pkz-R7jo/s1600/17+wild+things.jpg" target="_blank" rel="noreferrer"><img src="'+k+'" alt=""></a></p><p>这只看起来像兔子,让人耳目一新。但他那条鬼舌头是在开玩笑吗?当然啦,兔子不能长一条你以为它们该有的正常舌头,非得长一条荒谬的、迷你版的、像人类的舌头。</p><p><a href="https://2.bp.blogspot.com/-Lg3B9vKTNik/UgQb0-J3WQI/AAAAAAAAEsk/A1OjkA3YzZU/s1600/18+tongue.jpg" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p><p>终于,我们看到一只挺正常的、甚至可以说可爱的兔子——理所当然,他用一个讨人厌的空气引号手势把这一切给毁了:</p><p><a href="https://3.bp.blogspot.com/-npfwWegHp9E/UgQb1O_ighI/AAAAAAAAEs0/IuHX1X6O1I8/s1600/19+airquote.jpg" target="_blank" rel="noreferrer"><img src="'+j+'" alt=""></a></p><p>自尊心在兔子界本来就不是什么稀罕玩意儿,但这一只稳拿垫底奖:</p><p><a href="https://4.bp.blogspot.com/-1v9cs3gLDPY/UgQb2HDgGfI/AAAAAAAAEtA/q_AMWxCKpf4/s1600/20+low+self+esteem.jpeg" target="_blank" rel="noreferrer"><img src="'+d+'" alt=""></a></p><p>一只非主流兔:</p><p><a href="https://2.bp.blogspot.com/-etoWcbfEXzM/UgQb2Zyrw3I/AAAAAAAAEv4/Rsme-puDaR0/s1600/21+emo.jpg" target="_blank" rel="noreferrer"><img src="'+Q+'" alt=""></a></p><p>有人在外面买了只兔子,幻想着能跟这种东西一起玩(显然事先没去谷歌图片搜一下):</p><p><a href="https://1.bp.blogspot.com/-MBwE8K4ydJc/UgQb2quL0TI/AAAAAAAAEtc/zru_Ozw27FY/s1600/23+cute1.jpeg" target="_blank" rel="noreferrer"><img src="'+I+'" alt=""></a></p><p>然后落得这样一个结果,估计不会太开心:</p><p><a href="https://2.bp.blogspot.com/-uourzhn6VQ0/UgQb2l2-iuI/AAAAAAAAEtI/SA3uL73jahE/s1600/22+owners+pleased+with+how+that+turned+out.jpg" target="_blank" rel="noreferrer"><img src="'+E+'" alt=""></a></p><p>这里是我这辈子见过最诡异的两只动物:</p><p><a href="https://4.bp.blogspot.com/-QjMFZWH9WFk/UgQb25-RKyI/AAAAAAAAEtY/iF_cJuvocRM/s1600/24+owner.jpg" target="_blank" rel="noreferrer"><img src="'+U+'" alt=""></a></p><p>想象一下你半夜醒来,这俩就那么杵在你房间里,以一模一样的姿势,盯着你。恐怖至极。</p><p>快速插一句——你知道那种感觉吗,有时候你盯着一个单词看太久,它开始看起来怪怪的、不对劲?然后你突然不确定任何字该怎么拼了?我现在对兔子的照片就是这种感觉。我看了太多张了,现在什么都不确定了。比如这位小家伙:</p><p><a href="https://4.bp.blogspot.com/-vF3FPZQ07LE/UgQb3eO5NcI/AAAAAAAAEtk/miQVngCT_wU/s1600/25+dog.jpg" target="_blank" rel="noreferrer"><img src="'+T+'" alt=""></a></p><p>现在,这货在我眼里<em>完全</em>就是一只小狗。但我不确定它其实看起来是不是一只正常的兔子,只是我脑子已经烧坏了分辨不出来了。谁来告诉我一下。</p><p>继续。还有什么比一只嗑冰毒的兔子更适合作为下一位登场嘉宾呢。</p><p><a href="https://1.bp.blogspot.com/-TOagTG0dVGk/UgQb3uZSQCI/AAAAAAAAEts/rDjuTXQD000/s1600/26+meth+possum.jpg" target="_blank" rel="noreferrer"><img src="'+W+'" alt=""></a></p><p>这里我们有一位如假包换的盎格鲁-撒克逊白人新教徒 (WASP),正待在他玛莎葡萄园岛的庄园里。</p><p><a href="https://4.bp.blogspot.com/-10FW9sUbIbM/UgQb3wxTtqI/AAAAAAAAEt8/EmZQKVy6mpE/s1600/27+wasp.jpg" target="_blank" rel="noreferrer"><img src="'+M+'" alt=""></a></p><p>接下来出场的是我这辈子见过最愤怒的动物。正常动物生气是以动物的方式生气。但这只兔子是以人类的方式在暴怒。再一次,不正常。</p><p><a href="https://2.bp.blogspot.com/-h762M5aX5pQ/UgQb4BQC9II/AAAAAAAAEt4/xkm3I2OvhmQ/s1600/28+fucking+hate+me.jpeg" target="_blank" rel="noreferrer"><img src="'+v+'" alt=""></a></p><p>这里我们有两只兔子扮演人类爷爷奶奶,光是这个设定就已经够怪了,更别说棕色那只的耳朵到底他妈发生了什么事。</p><p><a href="https://3.bp.blogspot.com/-lvuqt_7SE0g/UgQb4cCbweI/AAAAAAAAEuM/MVm6iM9FMp4/s1600/29+grandparents+ear.jpg" target="_blank" rel="noreferrer"><img src="'+q+'" alt=""></a></p><p>Honey Boo Boo 的妈:</p><p><a href="https://2.bp.blogspot.com/-D-1yJr6Z1QE/UgQb43rPUUI/AAAAAAAAEuU/EAyt9pr6nFM/s1600/30+boo+boo.jpeg" target="_blank" rel="noreferrer"><img src="'+z+'" alt=""></a></p><p>刻薄的寄宿学校校长:</p><p><a href="https://2.bp.blogspot.com/-VAewqdAOQE4/UgQb5M09LaI/AAAAAAAAEuk/xko_XCPe96c/s1600/31+mean+headmaster.jpeg" target="_blank" rel="noreferrer"><img src="'+P+'" alt=""></a></p><p>70 年代的你妈。真的不太清楚一只兔子为什么会长成那样。</p><p><a href="https://3.bp.blogspot.com/-g_T4QL9rIi8/UgQb5khvoZI/AAAAAAAAEus/Xx77jDErZKo/s1600/33+m70s.jpg" target="_blank" rel="noreferrer"><img src="'+B+'" alt=""></a></p><p>这只兔子挺确定他后悔把这女孩带回自己公寓了:</p><p><a href="https://1.bp.blogspot.com/-hWcyO7hcUIo/UgQb6GdlZpI/AAAAAAAAEvE/CKczEkLRw8s/s1600/35+regrets+decision.jpg" target="_blank" rel="noreferrer"><img src="'+Y+'" alt=""></a></p><p>现在我们要进入超级诡异的领域了。这是一只货真价实的英国卡通角色兔子:</p><p><a href="https://2.bp.blogspot.com/-2w5TSAwiZsk/UgQb56HyyuI/AAAAAAAAEu8/mvybNCUzNiA/s1600/34+looney+tunes.jpg" target="_blank" rel="noreferrer"><img src="'+x+'" alt=""></a></p><p>一只忘记停止当胎儿的兔子:</p><p><a href="https://3.bp.blogspot.com/-xfI3IZT7-8E/UgQb6czrRpI/AAAAAAAAEvA/FOICuW1x_YY/s1600/36+forgot+to+stop+being+a+fetus.jpg" target="_blank" rel="noreferrer"><img src="'+O+'" alt=""></a></p><p><a href="https://2.bp.blogspot.com/-i2YZreFzG9g/UgQb6rBUoxI/AAAAAAAAEvM/dg1Q22keqnQ/s1600/37+back+in+animal+territory.jpg" target="_blank" rel="noreferrer"><img src="'+C+'" alt=""></a></p><p>一只他妈的鸡蛋兔子。我已经无所谓了。</p><p><a href="https://4.bp.blogspot.com/-5YGrdfVbwPo/UgQb670-OFI/AAAAAAAAEvU/MoMMfr0t_RI/s1600/38+come+on.jpg" target="_blank" rel="noreferrer"><img src="'+R+'" alt=""></a></p><p>哦看在上帝的份上,不是吧?你这辈子就一次机会,就整出这个玩意儿?下一个……</p><p><a href="https://1.bp.blogspot.com/-qYu4foflJbs/UgQb7JEAKkI/AAAAAAAAEvY/yKVH4O3XJh4/s1600/39+huge.jpg" target="_blank" rel="noreferrer"><img src="'+Z+'" alt=""></a></p><p>行吧,为什么不呢。到这份上已经没什么能让我惊讶的了。</p><p><a href="https://1.bp.blogspot.com/-5YDByEbEZRo/UgQb7UBoIQI/AAAAAAAAEvk/C71rSCwrwsI/s1600/40+come+on3.jpeg" target="_blank" rel="noreferrer"><img src="'+J+'" alt=""></a></p><p>恭喜你,云朵兔。我本以为我什么都见过了,结果你还能整出这一手。祝你人生愉快。</p><p>好了,我觉得今天就到这儿吧。既然知道了这残酷的真相,我再也没法用同样的眼光看兔子了,估计你也一样。</p><p>最后送你一只已经他妈受够了当兔子的兔子。可以理解。</p><h2 id="-1" tabindex="-1"><a href="https://4.bp.blogspot.com/-zJcUIVbTbLY/UgQb716mJoI/AAAAAAAAEvw/lw2vTw_7zhY/s1600/41+rock+bottom+2.jpeg" target="_blank" rel="noreferrer"><img src="'+L+'" alt=""></a> <a class="header-anchor" href="#-1" aria-label="Permalink to &quot;[![](/images/the-bunny-manifesto/41-rock-bottom-2.jpeg)](https://4.bp.blogspot.com/-zJcUIVbTbLY/UgQb716mJoI/AAAAAAAAEvw/lw2vTw_7zhY/s1600/41+rock+bottom+2.jpeg)&quot;">​</a></h2><p>感谢 <a href="http://dailybunny.org/" target="_blank" rel="noreferrer">The Daily Bunny</a> 提供了本文中许多最令人不安的图片。</p><h2 id="想知道这些奇怪的生物在假期里都在干嘛-请访问我们的-假期更新。" tabindex="-1">想知道这些奇怪的生物在假期里都在干嘛,请访问我们的 <a href="https://waitbutwhy.com/2013/12/wait-but-why-holiday-update.html" target="_blank" rel="noreferrer">假期更新</a>。 <a class="header-anchor" href="#想知道这些奇怪的生物在假期里都在干嘛-请访问我们的-假期更新。" aria-label="Permalink to &quot;想知道这些奇怪的生物在假期里都在干嘛,请访问我们的 [假期更新](https://waitbutwhy.com/2013/12/wait-but-why-holiday-update.html)。&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请注册我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会发送给你。</p><h2 id="如需支持-wait-but-why-请访问我们的-patreon-页面。" tabindex="-1">如需支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。 <a class="header-anchor" href="#如需支持-wait-but-why-请访问我们的-patreon-页面。" aria-label="Permalink to &quot;如需支持 Wait But Why,请访问我们的 **[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p><strong>Wait But Why 的另外三篇动物讨论:</strong></p><p><strong><a href="https://waitbutwhy.com/2013/10/the-primate-awards.html" target="_blank" rel="noreferrer">灵长类大奖</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/02/why-bugs-ruin-everything.html" target="_blank" rel="noreferrer">为什么虫子毁掉一切<br></a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/10/dark-secrets-bird-world.html" target="_blank" rel="noreferrer">鸟类世界的黑暗秘密</a></strong></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/08/the-bunny-manifesto.html&amp;description=The%20Bunny%20Manifesto" target="_blank" rel="noreferrer"><img src="'+D+'" alt=""></a></p>',112)])])}const tt=e(F,[["render",V]]);export{$ as __pageData,tt as default};
